+    /**
+     * {@return the number of Unicode code points in this character buffer}
+     *
+     * <p>The number of Unicode code points in this character buffer is
+     * the number of Unicode code points between the position (inclusive)
+     * and the limit (exclusive).
+     * Isolated surrogate code units count as one code point each.
+     *
+     * @since 27
+     */
+    public final int codePointCount() {
+        // Refer to the definition of length() (the above) and remaining() (Buffer.java)
+        int lim = limit();
+        int i = position();
+        int count = lim - i;
+        for (; i < lim;) {
+            if (Character.isHighSurrogate(get(i++)) && i < lim && Character.isLowSurrogate(get(i))) {
+                lim--;
+                i++;
+            }
+        }
+        return count;
+    }
+

